	if !ok {
		return state, false, writeCompactionDiagnostic(
			out,
			"manager compaction: skipped; no explicit usage input",
			stateFile,
			"",
			false,
		)
	}
	if percent <= 80 {
		return state, false, writeCompactionDiagnostic(
			out,
			fmt.Sprintf("manager compaction: skipped; usage %.1f%% <= 80%%", percent),
			stateFile,
			"",
			false,
		)
	}
