	if strings.TrimSpace(state.Delivery.ManagerPaneID) == "" {
		state.Delivery.ManagerPaneID = strings.TrimSpace(state.ManagerPaneID)
	}
	if err := stateStore(
		d,
		"",
		func() time.Time { return now },
	).Save(stateFile, state); err != nil {
		return state, false, err
	}
